// Extrai o post mais recente do feed RSS e verifica se ja foi postado
const items = $input.first().json.rss.channel.item;
const latest = Array.isArray(items) ? items[0] : items;

const slug = (latest.guid && typeof latest.guid === 'object' ? latest.guid['#'] : latest.guid || '')
  .split('/').pop();

// Static workflow data — guarda o ultimo slug postado
const staticData = $getWorkflowStaticData('global');
const lastPosted = staticData.lastInstagramPostSlug || '';

const isNew = slug && slug !== lastPosted;

const imageUrl = (latest['media:content'] && latest['media:content']['$']?.url) ||
                 (latest['media:thumbnail'] && latest['media:thumbnail']['$']?.url) ||
                 (latest.enclosure && latest.enclosure['$']?.url) ||
                 'https://www.izylaudo.com.br/static/site/images/og-image.jpg';

return [{
  json: {
    isNew,
    slug,
    lastPosted,
    title: latest.title,
    link: latest.link,
    summary: latest.description,
    author: latest.author,
    category: latest.category,
    imageUrl,
  }
}];

