// Extrai o texto gerado pelo Claude e prepara payload Instagram
const response = $input.first().json;
const caption = response.content?.[0]?.text || '';
const previousData = $('Verificar Post Novo').first().json;

return [{
  json: {
    caption,
    imageUrl: previousData.imageUrl,
    slug: previousData.slug,
    title: previousData.title,
    link: previousData.link,
  }
}];

// Salva slug postado pra nao postar de novo
const payload = $('Preparar Payload Instagram').first().json;
const publishResp = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.lastInstagramPostSlug = payload.slug;
staticData.lastInstagramPostId = publishResp.id;
staticData.lastInstagramPostAt = new Date().toISOString();
return [{ json: { ok: true, slug: payload.slug, instagramMediaId: publishResp.id, postedAt: staticData.lastInstagramPostAt } }];

